import React, { useState } from "react";
import { NavLink, useLocation } from "react-router-dom";
import { Badge } from "antd";
import {
  AiOutlineDashboard,
  AiOutlineUser,
  AiOutlineUsergroupAdd,
  AiOutlineCalendar,
  AiOutlineSchedule,
  AiOutlineShop,
  AiOutlineMoneyCollect,
  AiOutlineSwap,
  AiOutlineTeam,
  AiOutlineBell,
  AiOutlineSetting,
  AiOutlineQuestionCircle,
  AiOutlineLogout,
  AiOutlineMenu,
} from "react-icons/ai";
import { FiUsers, FiBookOpen } from "react-icons/fi";
import { BiBook, BiCalendarAlt } from "react-icons/bi";
import { BsCapslock, BsReceipt } from "react-icons/bs";

const menuGroups = [
  {
    title: "SETTINGS",
    items: [
      { label: "Dashboard", icon: <AiOutlineDashboard />, href: "/dashboard" },
      { label: "Học viên", icon: <AiOutlineUsergroupAdd />, href: "/students" },
      { label: "Giáo viên", icon: <AiOutlineUser />, href: "/teachers" },
      { label: "Quản lý lịch", icon: <AiOutlineCalendar />, href: "/schedules" },
      { label: "Kế hoạch thi", icon: <AiOutlineSchedule />, href: "/exam-plans" },
    ],
  },
  {
    title: "TÀI CHÍNH",
    items: [
      { label: "Sale", icon: <AiOutlineShop />, href: "/sales" },
      { label: "Các khoản thu chi", icon: <AiOutlineMoneyCollect />, href: "/payments" },
    ],
  },
  {
    title: "HỆ THỐNG",
    items: [
      { label: "Người dùng", icon: <FiUsers />, href: "/users" },
      { label: "Thông báo", icon: <AiOutlineBell />, href: "/notifications" },
      { label: "Hệ thống", icon: <AiOutlineSetting />, href: "/system" },
    ],
  },
];

const PhucAnSidebar = ({ collapsed, onToggle }) => {
  const { pathname } = useLocation();

  return (
    <div
      style={{
        width: collapsed ? "72px" : "240px",
        minHeight: "100vh",
        background: "#fff",
        borderRight: "1px solid #E5E7EB",
        display: "flex",
        flexDirection: "column",
        transition: "width 0.2s ease",
        position: "fixed",
        left: 0,
        top: 0,
        zIndex: 100,
        overflow: "hidden",
      }}
    >
      {/* Logo */}
      <div
        style={{
          padding: collapsed ? "20px 0" : "20px 20px",
          borderBottom: "1px solid #F3F4F6",
          display: "flex",
          alignItems: "center",
          gap: "10px",
          justifyContent: collapsed ? "center" : "flex-start",
          minHeight: "70px",
        }}
      >
        <div
          style={{
            width: 36,
            height: 36,
            borderRadius: 8,
            background: "linear-gradient(135deg, #F59E0B, #FBBF24)",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontWeight: 800,
            fontSize: 15,
            color: "#fff",
            flexShrink: 0,
            letterSpacing: "-0.5px",
          }}
        >
          PA
        </div>
        {!collapsed && (
          <div>
            <div
              style={{
                fontWeight: 800,
                fontSize: 16,
                color: "#1F2937",
                letterSpacing: "0.5px",
                lineHeight: 1.2,
              }}
            >
              PHÚC AN
            </div>
            <div
              style={{
                fontSize: 10,
                color: "#9CA3AF",
                fontWeight: 500,
                letterSpacing: "1px",
                marginTop: 1,
              }}
            >
              TRUNG TÂM
            </div>
          </div>
        )}
      </div>

      {/* Menu */}
      <div style={{ flex: 1, overflowY: "auto", overflowX: "hidden", padding: "12px 0" }}>
        {menuGroups.map((group) => (
          <div key={group.title} style={{ marginBottom: "20px" }}>
            {!collapsed && (
              <div
                style={{
                  fontSize: 10,
                  fontWeight: 700,
                  color: "#9CA3AF",
                  letterSpacing: "1.5px",
                  padding: "0 20px",
                  marginBottom: "6px",
                }}
              >
                {group.title}
              </div>
            )}
            {group.items.map((item) => {
              const isActive = pathname === item.href || pathname.startsWith(item.href + "/");
              return (
                <div key={item.href}>
                  {collapsed ? (
                    <NavLink
                      to={item.href}
                      title={item.label}
                      style={{
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "center",
                        padding: "10px",
                        margin: "2px 8px",
                        borderRadius: 8,
                        color: isActive ? "#3B82F6" : "#6B7280",
                        background: isActive ? "#EFF6FF" : "transparent",
                        fontSize: 18,
                        transition: "all 0.15s",
                        textDecoration: "none",
                      }}
                    >
                      {item.icon}
                    </NavLink>
                  ) : (
                    <NavLink
                      to={item.href}
                      style={{
                        display: "flex",
                        alignItems: "center",
                        gap: "10px",
                        padding: "9px 20px",
                        margin: "1px 8px",
                        borderRadius: 8,
                        color: isActive ? "#3B82F6" : "#4B5563",
                        background: isActive ? "#EFF6FF" : "transparent",
                        fontWeight: isActive ? 600 : 400,
                        fontSize: 13,
                        transition: "all 0.15s",
                        textDecoration: "none",
                      }}
                    >
                      <span style={{ fontSize: 16, flexShrink: 0 }}>{item.icon}</span>
                      <span>{item.label}</span>
                    </NavLink>
                  )}
                </div>
              );
            })}
          </div>
        ))}
      </div>

      {/* Bottom */}
      <div
        style={{
          borderTop: "1px solid #F3F4F6",
          padding: "12px 0",
        }}
      >
        {collapsed ? (
          <>
            <div
              title="Help"
              style={{
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                padding: "10px",
                margin: "2px 8px",
                borderRadius: 8,
                color: "#6B7280",
                cursor: "pointer",
                fontSize: 18,
              }}
            >
              <AiOutlineQuestionCircle />
            </div>
            <div
              title="Logout"
              style={{
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                padding: "10px",
                margin: "2px 8px",
                borderRadius: 8,
                color: "#EF4444",
                cursor: "pointer",
                fontSize: 18,
              }}
            >
              <AiOutlineLogout />
            </div>
          </>
        ) : (
          <>
            <div
              style={{
                display: "flex",
                alignItems: "center",
                gap: "10px",
                padding: "9px 20px",
                margin: "1px 8px",
                borderRadius: 8,
                color: "#6B7280",
                cursor: "pointer",
                fontSize: 13,
              }}
            >
              <AiOutlineQuestionCircle style={{ fontSize: 16 }} />
              <span>Help</span>
            </div>
            <div
              style={{
                display: "flex",
                alignItems: "center",
                gap: "10px",
                padding: "9px 20px",
                margin: "1px 8px",
                borderRadius: 8,
                color: "#EF4444",
                cursor: "pointer",
                fontSize: 13,
                fontWeight: 500,
              }}
            >
              <AiOutlineLogout style={{ fontSize: 16 }} />
              <span>Logout Account</span>
            </div>
          </>
        )}
      </div>
    </div>
  );
};

export default PhucAnSidebar;

import React, { useEffect } from "react";
import AppBreadcrumb from "../../components/Breadcumb";
import ChartsDashboard from "./chart";
import { useDispatch } from "react-redux";
import { clearFilterDashboard } from "../../stores/slices/dashboard.slice";
import PageAccessGate from "../../components/pageAccess/PageAccessGate";

const Dashboard = () => {
  const dispatch = useDispatch();
  useEffect(() => {
    return () => {
      dispatch(clearFilterDashboard());
    };
  }, []);
  return (
    <>
      <PageAccessGate permissionsNeeded={["dashboard.view"]}>
        <AppBreadcrumb items={[{ title: "Dashboard", href: "/dashboard" }]} />
        <ChartsDashboard />
      </PageAccessGate>
    </>
  );
};

export default Dashboard;

